def collapse_delims(s):
    delimiters = ',; '
    pieces = s.split(delimiters)
    # handle edge case of a single delimiter at the start or end
    if not pieces and s[-1] in delimiters:
        pieces = [s[1:]] if s[0] in delimiters else [s[:-1]]
    # remove empty pieces at the start and end, then join remaining pieces with a single comma
    return ', '.join(filter(None, pieces))
